      "  color: var(--text) !important;",
      "  font-size: clamp(2.65rem, 5.2vw, 3.8rem) !important;",
      "  font-weight: 920 !important;",
      "  line-height: 0.9 !important;",
      "  letter-spacing: -0.065em !important;",
      "  font-variant-numeric: tabular-nums !important;",
      "}",
