      "transition:background .15s ease,color .15s ease;}",
      ".rme-charts-close:hover{",
      "background:color-mix(in srgb,var(--text) 8%,transparent);color:var(--text);}",
      ".rme-charts-grid{display:grid;grid-template-columns:1fr;gap:0.85rem;}",
