      "color-mix(in srgb,#f1f5f9 26%,transparent) 100%);",
      "-webkit-backdrop-filter:blur(22px) saturate(138%);",
      "backdrop-filter:blur(22px) saturate(138%);",
      "border:1px solid color-mix(in srgb,#fff 40%,#94a3b8 10%);",
