      ".notion-ws-pane[data-rme-tps=\"1\"] [class*=\"chevron\"],",
      ".notion-ws-pane[data-rme-tps=\"1\"] .ws-pane-toggle,",
      ".notion-ws-pane[data-rme-tps=\"1\"] > summary,",
